const headers = $json.headers || {};
const role = String(headers["x-user-role"] || "").trim().toLowerCase();
const id = String(headers["x-user-id"] || role || "").trim();
const name = String(headers["x-user-name"] || role || "").trim();

if (!role) {
  return { json: { statusCode: 401, error: "expired", code: "session_missing" } };
}

return {
  json: {
    session: { id, name, role },
    body: $json.body,
  },
};

const CONFIG = {
  AIRTABLE_PAT: "REPLACE_WITH_AIRTABLE_PAT",
  AIRTABLE_BASE_ID: "REPLACE_WITH_AIRTABLE_BASE_ID",
  AIRTABLE_EPISODE_IMAGE_FIELD: "cover_image",
};
const request = this.helpers.httpRequest.bind(this.helpers);
const apiKey = CONFIG.AIRTABLE_PAT;
const baseId = CONFIG.AIRTABLE_BASE_ID;
const session = $json.session;
const body = $json.body || {};

if (!apiKey || !baseId || apiKey.includes("REPLACE_WITH") || baseId.includes("REPLACE_WITH")) {
  return { json: { statusCode: 500, error: "Airtable config missing in n8n code node", code: "airtable_config_missing" } };
}

if (!session || !["samuel", "mathilde"].includes(session.role)) {
  return { json: { statusCode: 403, error: "forbidden", code: "episode_create_forbidden" } };
}

const title = String(body.title || "").trim();
const date = String(body.date || "").trim();
const place = String(body.place || "").trim();
const duration = String(body.duration || "").trim();
const coverUrl = String(body.cover_url || "").trim();
const notes = String(body.notes || "").trim();
const musicUrl = String(body.music_url || "").trim();
const image = body.image_attachment || null;

if (!title || !date || !place) {
  return { json: { statusCode: 400, error: "title, date and place are required", code: "episode_invalid" } };
}

const airtable = "https://api.airtable.com/v0/" + baseId;
const headers = { Authorization: "Bearer " + apiKey };
const listUrl = airtable + "/Episodes?fields%5B%5D=number&sort%5B0%5D%5Bfield%5D=number&sort%5B0%5D%5Bdirection%5D=desc&maxRecords=1";

let listData;
try {
  listData = await request({ method: "GET", url: listUrl, headers, json: true });
} catch (error) {
  return { json: { statusCode: 500, error: "Airtable episodes lookup failed: " + (error?.message || String(error)), code: "airtable_episodes_failed" } };
}

const maxNumber = Number(listData.records?.[0]?.fields?.number || 0);
const number = maxNumber + 1;
const fields = { title, date, place, number };
if (duration) fields.duration = duration;
if (coverUrl) fields.cover_url = coverUrl;
if (notes) fields.notes = notes;
if (musicUrl) fields.music_url = musicUrl;

let created;
try {
  created = await request({
    method: "POST",
    url: airtable + "/Episodes",
    headers,
    body: { fields },
    json: true,
  });
} catch (error) {
  return { json: { statusCode: 500, error: "Airtable episode create failed: " + (error?.message || String(error)), code: "airtable_episode_create_failed" } };
}

let finalFields = created.fields;
let uploadedCoverUrl = finalFields.cover_url || "";

if (image?.file) {
  const attachmentField = CONFIG.AIRTABLE_EPISODE_IMAGE_FIELD || "cover_image";
  const file = String(image.file || "").replace(/^data:.*?;base64,/, "");
  const filename = String(image.filename || "date-" + Date.now() + ".jpg").trim();
  const contentType = String(image.contentType || "image/jpeg").trim();

  if (file.length > 7_000_000) {
    return { json: { statusCode: 413, error: "Image too large", code: "image_too_large" } };
  }

  const uploadUrl = airtable + "/" + created.id + "/" + encodeURIComponent(attachmentField) + "/uploadAttachment";
  let uploaded;
  try {
    uploaded = await request({
      method: "POST",
      url: uploadUrl,
      headers,
      body: { file, filename, contentType },
      json: true,
    });
  } catch (error) {
    return { json: { statusCode: 500, error: "Airtable image upload failed: " + (error?.message || String(error)), code: "airtable_image_upload_failed" } };
  }

  finalFields = uploaded.fields || finalFields;
  const attachments = finalFields[attachmentField] || [];
  uploadedCoverUrl = attachments[0]?.url || uploadedCoverUrl;

  if (uploadedCoverUrl) {
    try {
      const patched = await request({
        method: "PATCH",
        url: airtable + "/Episodes/" + created.id,
        headers,
        body: { fields: { cover_url: uploadedCoverUrl } },
        json: true,
      });
      finalFields = patched.fields || finalFields;
    } catch {}
  }
}

const f = finalFields;
return {
  json: {
    episode: {
      id: created.id,
      number: f.number,
      title: f.title,
      date: f.date,
      place: f.place,
      duration: f.duration || "",
      cover_url: f.cover_url || uploadedCoverUrl || "",
      notes: f.notes || "",
      music_url: f.music_url || "",
    },
  },
};
